import Link from "next/link";

function SciSeekLogo({ className = "h-7 w-7" }: { className?: string }) {
  return (
    <div
      className={`relative flex items-center justify-center rounded-xl border border-[var(--border)] bg-[var(--panel)]/80 ${className}`}
    >
      <svg
        viewBox="0 0 64 64"
        className="h-[80%] w-[80%]"
        fill="none"
        aria-hidden="true"
      >
        <circle cx="32" cy="32" r="6.5" fill="#22d3ee" />
        <ellipse
          cx="32"
          cy="32"
          rx="20"
          ry="12"
          stroke="#22d3ee"
          strokeWidth="3"
        />
        <ellipse
          cx="32"
          cy="32"
          rx="20"
          ry="12"
          transform="rotate(60 32 32)"
          stroke="#22d3ee"
          strokeWidth="3"
          opacity="0.75"
        />
        <circle cx="48" cy="30" r="3" fill="#fde047" />
      </svg>
    </div>
  );
}

type PageShellProps = {
  title: string;
  subtitle?: string;
  children: React.ReactNode;
};

export default function PageShell({
  title,
  subtitle,
  children,
}: PageShellProps) {
  return (
    <div className="min-h-screen bg-[var(--background)] text-[var(--foreground)]">
      <header className="sticky top-0 z-20 border-b border-[var(--border)] bg-[var(--background)]/80 backdrop-blur">
        <div className="mx-auto flex w-full max-w-5xl items-center justify-between gap-4 px-4 py-4 sm:px-6">
          <Link href="/" className="flex min-w-0 items-center gap-3">
            <SciSeekLogo className="h-12 w-12" />
            <div className="min-w-0">
              <div className="text-xl font-semibold tracking-tight text-white sm:text-2xl">
                SciSeek
              </div>
              <div className="text-xs text-[var(--muted)] sm:text-sm">
                Search smarter. Understand deeper.
              </div>
            </div>
          </Link>

          <nav className="hidden items-center gap-2 md:flex">
            <Link
              href="/about"
              className="rounded-lg px-3 py-2 text-sm text-white/70 transition hover:bg-white/5 hover:text-white"
            >
              About
            </Link>
            <Link
              href="/story"
              className="rounded-lg px-3 py-2 text-sm text-white/70 transition hover:bg-white/5 hover:text-white"
            >
              Story
            </Link>
            <Link
              href="/contact"
              className="rounded-lg px-3 py-2 text-sm text-white/70 transition hover:bg-white/5 hover:text-white"
            >
              Contact
            </Link>
          </nav>
        </div>
      </header>

      <main className="mx-auto w-full max-w-3xl px-6 py-12">
        <div className="rounded-3xl border border-[var(--border)] bg-[var(--card)] p-8 shadow-[0_0_0_1px_rgba(96,165,250,0.04),0_10px_30px_rgba(0,0,0,0.18)]">
          <h1 className="text-3xl font-semibold tracking-tight text-white sm:text-4xl">
            {title}
          </h1>

          {subtitle ? (
            <p className="mt-3 max-w-2xl text-[var(--muted)]">{subtitle}</p>
          ) : null}

          <div className="prose prose-invert mt-8 max-w-none prose-p:text-[var(--foreground)] prose-p:leading-7 prose-li:text-[var(--foreground)] prose-strong:text-white prose-headings:text-white">
            {children}
          </div>
        </div>
      </main>
    </div>
  );
}